import{c as e,Q as a,j as r,m as s}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Hindsight is 20/20: Building Agent Memory that Retains, Recalls, and Reflects","description":"","frontmatter":{"title":"Hindsight is 20/20: Building Agent Memory that Retains, Recalls, and Reflects","arxiv_id":2512.12818,"authors":"Chris Latimer, Nicoló Boschi, Andrew Neeser, Chris Bartholomew, Gaurav Srivastava, Xuan Wang, Naren Ramakrishnan","published":"2025-12-14T00:00:00.000Z","source":"https://arxiv.org/abs/2512.12818","source_tier":"P"},"headers":[],"relativePath":"research/papers/2025-12-14-hindsight-agent-memory-retain-recall-reflect-2512-12818.md","filePath":"research/papers/2025-12-14-hindsight-agent-memory-retain-recall-reflect-2512-12818.md","lastUpdated":1779901665000}'),i={name:"research/papers/2025-12-14-hindsight-agent-memory-retain-recall-reflect-2512-12818.md"};function n(o,t,l,d,h,g){return a(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="hindsight-is-20-20-building-agent-memory-that-retains-recalls-and-reflects" tabindex="-1">Hindsight is 20/20: Building Agent Memory that Retains, Recalls, and Reflects <a class="header-anchor" href="#hindsight-is-20-20-building-agent-memory-that-retains-recalls-and-reflects" aria-label="Permalink to &quot;Hindsight is 20/20: Building Agent Memory that Retains, Recalls, and Reflects&quot;">​</a></h1><p><strong>ArXiv</strong>: 2512.12818 | <strong>Date</strong>: 2025-12-14 | <strong>Authors</strong>: Chris Latimer, Nicoló Boschi, Andrew Neeser, Chris Bartholomew, Gaurav Srivastava, Xuan Wang, Naren Ramakrishnan | <strong>Category</strong>: cs.CL</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>引入 Hindsight 記憶架構，提升 LLM agent 跨多個 session 累積和利用經驗的能力。核心批評：「現有方法模糊了證據與推理之間的界線，難以在長視地平線上組織資訊，且對需要解釋推理過程的 agent 支援有限。」</p><h2 id="四網絡記憶架構" tabindex="-1">四網絡記憶架構 <a class="header-anchor" href="#四網絡記憶架構" aria-label="Permalink to &quot;四網絡記憶架構&quot;">​</a></h2><p>Hindsight 將記憶組織為四個不同的邏輯網絡：</p><ol><li><strong>World facts</strong>（世界事實）：關於環境的客觀知識</li><li><strong>Agent experiences</strong>（Agent 經驗）：具體互動記錄</li><li><strong>Synthesized entity summaries</strong>（實體摘要）：跨 session 的實體知識抽象</li><li><strong>Evolving beliefs</strong>（演化信念）：動態更新的推斷和假設</li></ol><h2 id="三核心功能" tabindex="-1">三核心功能 <a class="header-anchor" href="#三核心功能" aria-label="Permalink to &quot;三核心功能&quot;">​</a></h2><ul><li><strong>Retain</strong>（保留）：資訊添加到記憶網絡</li><li><strong>Recall</strong>（召回）：查詢記憶</li><li><strong>Reflect</strong>（反思）：更新現有記憶表示</li></ul><p>時間和實體感知設計，將對話流轉化為結構化的可查詢記憶。</p><h2 id="主要量化結果" tabindex="-1">主要量化結果 <a class="header-anchor" href="#主要量化結果" aria-label="Permalink to &quot;主要量化結果&quot;">​</a></h2><table tabindex="0"><thead><tr><th>基準</th><th>Hindsight 結果</th><th>比較基準</th></tr></thead><tbody><tr><td>LongMemEval（20B 開源模型）</td><td><strong>83.6%</strong></td><td>全上下文基線 39%（相同骨幹）</td></tr><tr><td>LongMemEval（更大骨幹）</td><td><strong>91.4%</strong></td><td>—</td></tr><tr><td>LoCoMo（更大骨幹）</td><td><strong>89.61%</strong></td><td>最強先前開源系統 75.78%</td></tr></tbody></table><p><strong>關鍵：83.6% 超過 GPT-4o 在同一任務的表現（20B 開源 vs GPT-4o）。</strong></p><h2 id="與現有記憶系統的差異" tabindex="-1">與現有記憶系統的差異 <a class="header-anchor" href="#與現有記憶系統的差異" aria-label="Permalink to &quot;與現有記憶系統的差異&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系統</th><th>記憶組織</th><th>可解釋性</th></tr></thead><tbody><tr><td>向量 RAG</td><td>語義空間</td><td>低（黑盒檢索）</td></tr><tr><td>A-MEM（2502.12110）</td><td>Zettelkasten 互聯</td><td>中</td></tr><tr><td><strong>Hindsight</strong></td><td>四網絡 + 顯式角色</td><td><strong>高（網絡類型清晰）</strong></td></tr></tbody></table><h2 id="對-workspace-的意義" tabindex="-1">對 Workspace 的意義 <a class="header-anchor" href="#對-workspace-的意義" aria-label="Permalink to &quot;對 Workspace 的意義&quot;">​</a></h2><p>Hindsight 的四網絡架構與 workspace MEMORY.md 的設計問題直接相關：</p><ul><li>「world facts」對應系統知識（CLAUDE.md 規則）</li><li>「agent experiences」對應 session 記錄</li><li>「evolving beliefs」對應學習到的決策模式</li></ul><p>LongMemEval 83.6% vs 39%（全上下文）= 結構化記憶 vs 原始長上下文的具體量化差異。</p><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Memory Architecture</strong> — 四網絡分類架構 + 83.6% LongMemEval 是目前記憶系統最強基準之一，超越 GPT-4o 的開源 20B 模型結果特別值得注意。</p>',21)])])}const p=e(i,[["render",n]]);export{m as __pageData,p as default};
